import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { PackagePlus, Store } from 'lucide-react';
import { generarNombreImagen, DICCIONARIO_PRODUCTOS, URL_CARPETA_IMAGENES } from '../utils/helpers';
import CargaMasiva from './CargaMasiva';

const DashboardVendedor = () => {
  const [localActivo, setLocalActivo] = useState(null);
  const [sugerencias, setSugerencias] = useState([]);
  const [form, setForm] = useState({ 
    categoria: 'Almacén', tipo: '', marca: '', contenido: '', 
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  useEffect(() => {
    const local = JSON.parse(localStorage.getItem('local-actual'));
    setLocalActivo(local);
  }, []);

  const handleTipoChange = (val) => {
    setForm({ ...form, tipo: val });
    if (val.length > 1) {
      const filtradas = DICCIONARIO_PRODUCTOS[form.categoria]?.filter(i => 
        i.toLowerCase().includes(val.toLowerCase())
      ) || [];
      setSugerencias(filtradas);
    } else { setSugerencias([]); }
  };

  const publicarIndividual = async (e) => {
    e.preventDefault();
    const publicId = generarNombreImagen(form.tipo, form.marca, form.contenido);
    
    const oferta = {
      producto: `${form.tipo} ${form.marca} ${form.contenido}`,
      categoria: form.categoria,
      precioNuevo: Number(form.precioNuevo),
      precioViejo: Number(form.precioViejo),
      stock: Number(form.stock),
      publicId: publicId,
      local: localActivo?._id || localActivo?.id,
      fechaVencimiento: form.fechaVencimiento
    };

    try {
      await axios.post(`${process.env.REACT_APP_API_URL}/api/ofertas`, oferta);
      alert("✅ Producto guardado. Asegúrate de que la imagen en Cloudinary se llame: " + publicId + ".jpg");
      setForm({ ...form, tipo: '', marca: '', contenido: '', precioNuevo: '', precioViejo: '', stock: '' });
    } catch (err) { alert("Error de conexión"); }
  };

  const previewUrl = `${URL_CARPETA_IMAGENES}${generarNombreImagen(form.tipo, form.marca, form.contenido)}.jpg`;

  return (
    <div style={{ padding: '20px', maxWidth: '700px', margin: '0 auto', fontFamily: 'sans-serif' }}>
      <header style={{ marginBottom: '20px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>Gestión de Productos</h2>
        <div style={{ background: '#e0f2fe', color: '#0369a1', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem' }}>
          {localActivo?.nombre || 'Local no seleccionado'}
        </div>
      </header>

      <CargaMasiva localId={localActivo?._id || localActivo?.id} onComplete={() => {}} />

      <form onSubmit={publicarIndividual} style={formStyle}>
        <h3 style={{ fontSize: '0.9rem', margin: '0 0 10px 0', borderBottom: '1px solid #f1f5f9', paddingBottom: '10px' }}>Nuevo Producto (Pasillo: {form.categoria})</h3>
        
        <label style={labelStyle}>Categoría</label>
        <select style={inputStyle} value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
          {Object.keys(DICCIONARIO_PRODUCTOS).map(c => <option key={c} value={c}>{c}</option>)}
        </select>

        <div style={{ position: 'relative' }}>
          <label style={labelStyle}>Tipo de Producto</label>
          <input style={inputStyle} placeholder="Escribe para buscar..." value={form.tipo} onChange={e => handleTipoChange(e.target.value)} required />
          {sugerencias.length > 0 && (
            <div style={suggestionBox}>
              {sugerencias.map(s => (
                <div key={s} style={sugItem} onClick={() => { setForm({...form, tipo: s}); setSugerencias([]); }}>{s}</div>
              ))}
            </div>
          )}
        </div>

        <div style={{ display: 'flex', gap: '10px' }}>
          <input style={inputStyle} placeholder="Marca" value={form.marca} onChange={e => setForm({...form, marca: e.target.value})} required />
          <input style={inputStyle} placeholder="Peso/Contenido (Ej: 1kg)" value={form.contenido} onChange={e => setForm({...form, contenido: e.target.value})} required />
        </div>

        <div style={{ display: 'flex', gap: '10px' }}>
          <input type="number" style={inputStyle} placeholder="Precio Oferta" value={form.precioNuevo} onChange={e => setForm({...form, precioNuevo: e.target.value})} required />
          <input type="number" style={inputStyle} placeholder="Stock" value={form.stock} onChange={e => setForm({...form, stock: e.target.value})} required />
          <input type="date" style={inputStyle} value={form.fechaVencimiento} onChange={e => setForm({...form, fechaVencimiento: e.target.value})} required />
        </div>

        {form.tipo && form.marca && (
          <div style={{ padding: '10px', background: '#f8fafc', borderRadius: '8px', textAlign: 'center', border: '1px solid #e2e8f0' }}>
            <p style={{ fontSize: '0.6rem', color: '#64748b' }}>Previsualización (Si la imagen existe en carpeta Productos):</p>
            <img src={previewUrl} alt="Preview" style={{ width: '70px', height: '70px', objectFit: 'contain' }} onError={(e) => e.target.style.display = 'none'} />
          </div>
        )}

        <button type="submit" style={btnStyle}><PackagePlus size={18} /> Publicar Producto</button>
      </form>
    </div>
  );
};

const formStyle = { background: 'white', padding: '20px', borderRadius: '15px', border: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', gap: '12px' };
const labelStyle = { fontSize: '0.65rem', fontWeight: '900', color: '#64748b', textTransform: 'uppercase' };
const inputStyle = { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box', outline: 'none' };
const btnStyle = { background: '#0369a1', color: 'white', padding: '12px', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '8px' };
const suggestionBox = { position: 'absolute', background: 'white', border: '1px solid #ccc', width: '100%', zIndex: 10, borderRadius: '8px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' };
const sugItem = { padding: '10px', cursor: 'pointer', borderBottom: '1px solid #eee' };

export default DashboardVendedor;
